def strip_diacritics(s):
    # remove arabic diacritics
    arabic_diacritics = re.compile(r'[\u0610-\u061A\u064B-\u065F\u06D6-\u06ED]')
    return arabic_diacritics.sub('', s)

def normalize_arabic(s):
    s = strip_diacritics(s)
    s = s.replace('ـ', '')  # tatweel
    # unify variations of alef, ya, ta marbuta, hamza forms
    s = s.replace('أ','ا').replace('إ','ا').replace('آ','ا')
    s = s.replace('ى','ي')  # unify alef maqsura to ya for search
    s = s.replace('ؤ','و').replace('ئ','ي').replace('ء','')
    s = s.replace('ۀ','ه').replace('ة','ه')
    s = re.sub(r'[^\u0600-\u06FF0-9 ]+', ' ', s)  # remove punctuation but keep arabic
    s = re.sub(r'\s+', ' ', s).strip()
    return s

def search_quran_contains(needle):
    norm_needle = normalize_arabic(needle)
    results = []
    for idx, ayah in enumerate(quran):
        text = ayah['ayah_text']
        if norm_needle in normalize_arabic(text):
            results.append((idx, ayah))
    return results

def search_quran_tokens(tokens):
    # tokens: list of token strings (already normalized)
    results = []
    for idx, ayah in enumerate(quran):
        norm_text = normalize_arabic(ayah['ayah_text'])
        if all(tok in norm_text for tok in tokens):
            results.append((idx, ayah))
    return results

