def lcs(a, b):
    n, m = len(a), len(b)
    dp = [[0]*(m+1) for _ in range(n+1)]
    for i in range(n-1, -1, -1):
        for j in range(m-1, -1, -1):
            if a[i]==b[j]:
                dp[i][j] = 1+dp[i+1][j+1]
            else:
                dp[i][j] = max(dp[i+1][j], dp[i][j+1])
    # reconstruct
    i=j=0
    res=[]
    while i<n and j<m:
        if a[i]==b[j]:
            res.append(a[i]); i+=1; j+=1
        elif dp[i+1][j]>=dp[i][j+1]:
            i+=1
        else:
            j+=1
    return ''.join(res)
